import{_ as o,o as e,c as r,ag as a}from"./chunks/framework.OsDJF_Ea.js";const d="/docs/modules/looper.png",g=JSON.parse('{"title":"Looper","description":"","frontmatter":{},"headers":[],"relativePath":"modules/looper.md","filePath":"modules/looper.md"}'),s={name:"modules/looper.md"};function i(n,t,l,p,u,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="looper" tabindex="-1">Looper <a class="header-anchor" href="#looper" aria-label="Permalink to &quot;Looper&quot;">​</a></h1><p><strong>Category:</strong> Granular / Looping</p><p>20-second looper with clean additive overdub, adjustable feedback, reverse playback, variable tape speed, and non-destructive loop region selection via start/size controls. Dry signal always passes through.</p><img src="'+d+'" alt="looper module"><h2 id="inputs" tabindex="-1">Inputs <a class="header-anchor" href="#inputs" aria-label="Permalink to &quot;Inputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>inL</strong> (audio)</td><td>Left audio to record.</td></tr><tr><td><strong>inR</strong> (audio)</td><td>Right audio to record.</td></tr><tr><td><strong>record</strong></td><td>Gate: 1 = recording/overdubbing, 0 = playback. Connect a Button.</td></tr><tr><td><strong>decay</strong></td><td>Overdub feedback 0-1. 1.0 = infinite (clean overdub), 0.707 = Frippertronics (-3dB/pass), 0 = replace.</td></tr><tr><td><strong>reverse</strong></td><td>Short pulse (&lt;500ms) toggles reverse, sustained hold (&gt;500ms) reverses while held.</td></tr><tr><td><strong>speed</strong></td><td>Playback speed CV. 0.5 = normal. Exponential: 0 = 0.25x, 0.5 = 1x, 1.0 = 4x.</td></tr><tr><td><strong>loopStart</strong></td><td>Loop region start position 0-1. Sweep with a pot to scan through the recorded buffer.</td></tr><tr><td><strong>loopSize</strong></td><td>Loop region size 0-1. Minimum ~1.5ms (64 samples). Shrink to isolate moments within the loop.</td></tr></tbody></table><h2 id="outputs" tabindex="-1">Outputs <a class="header-anchor" href="#outputs" aria-label="Permalink to &quot;Outputs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Port</th><th>Description</th></tr></thead><tbody><tr><td><strong>outL</strong> (audio)</td><td>Left audio (dry + loop).</td></tr><tr><td><strong>outR</strong> (audio)</td><td>Right audio (dry + loop).</td></tr><tr><td><strong>position</strong></td><td>Playback position 0-1.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><p>At feedback=1.0, overdubs layer infinitely with zero quality loss. Set feedback to 0.7 for Frippertronics: layers build then gradually fade. Use loopStart/loopSize with pots to scrub through and isolate regions of the recorded loop. Modulate speed with an LFO for tape-warble.</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2>',11)])])}const b=o(s,[["render",i]]);export{g as __pageData,b as default};
